// Test that /api/weather-grid returns a valid 5x5 grid of cloud/pressure data
async function testWeatherGridEndpoint() {
  const res = await fetch('http://localhost:3001/api/weather-grid?lat=41.35&lon=2.17');
  assertEquals(res.status, 200, 'Weather grid should return 200');

  const data = await res.json();

  // Should have grid array
  assert(Array.isArray(data.grid), 'Response should contain a grid array');
  assertEquals(data.grid.length, 25, 'Grid should have 25 points (5x5)');

  // Check center coordinates are echoed back
  assert(typeof data.centerLat === 'number', 'Should include centerLat');
  assert(typeof data.centerLon === 'number', 'Should include centerLon');

  // Validate first grid point structure
  const point = data.grid[0];
  assert(typeof point.lat === 'number', 'Grid point should have lat');
  assert(typeof point.lon === 'number', 'Grid point should have lon');
  assert(typeof point.cloudCover === 'number', 'Grid point should have cloudCover');
  assert(typeof point.pressure === 'number', 'Grid point should have pressure');
  assert(Array.isArray(point.hourly), 'Grid point should have hourly array');

  // Validate hourly entry structure
  if (point.hourly.length > 0) {
    const hourEntry = point.hourly[0];
    assert(typeof hourEntry.time === 'string', 'Hourly entry should have time');
    assert(typeof hourEntry.cloudCover === 'number', 'Hourly entry should have cloudCover');
    assert(typeof hourEntry.pressure === 'number', 'Hourly entry should have pressure');
  }

  // Validate pressure range (sanity check — should be 900-1100 hPa)
  assert(point.pressure > 900 && point.pressure < 1100, 'Pressure should be in reasonable range');

  // Validate cloud cover range (0-100%)
  assert(point.cloudCover >= 0 && point.cloudCover <= 100, 'Cloud cover should be 0-100%');
}
